head.b:skin:
/*==========================================================
                    CSS FRAMEWORK
==========================================================*/

/*----------------------------------------------------------
01. ROOT VARIABLES
----------------------------------------------------------*/

:root{

/* Brand Colors */

--primary:#0d6efd;
--primary-dark:#0b5ed7;
--secondary:#ff6b00;

--success:#198754;
--danger:#dc3545;
--warning:#ffc107;
--info:#0dcaf0;

/* Background */

--body-bg:#f5f7fb;
--card-bg:#ffffff;

/* Text */

--text:#222222;
--text-light:#666666;
--heading:#111111;

/* Border */

--border:#e5e7eb;

/* Radius */

--radius-xs:4px;
--radius-sm:6px;
--radius:10px;
--radius-lg:16px;

/* Shadow */

--shadow-sm:0 2px 6px rgba(0,0,0,.06);
--shadow:0 8px 25px rgba(0,0,0,.08);
--shadow-lg:0 15px 40px rgba(0,0,0,.12);

/* Container */

--container:1280px;

/* Header */

--header-height:72px;

/* Transition */

--transition:.30s ease;

/* Font */

--font:
Arial,
Helvetica,
sans-serif;

}

/*----------------------------------------------------------
02. CSS RESET
----------------------------------------------------------*/

*,
*::before,
*::after{

margin:0;
padding:0;
box-sizing:border-box;

}

html{

scroll-behavior:smooth;

}

body{

background:var(--body-bg);

font-family:var(--font);

font-size:16px;

line-height:1.7;

color:var(--text);

overflow-x:hidden;

text-rendering:optimizeLegibility;

-webkit-font-smoothing:antialiased;

}

img{

display:block;

max-width:100%;

height:auto;

}

a{

text-decoration:none;

color:inherit;

transition:var(--transition);

}

ul,
ol{

list-style:none;

}

button,
input,
textarea,
select{

font:inherit;

outline:none;

border:none;

background:none;

}

table{

border-collapse:collapse;

width:100%;

}

/*----------------------------------------------------------
03. LAYOUT
----------------------------------------------------------*/

.container{

width:100%;

max-width:var(--container);

margin:auto;

padding:0 18px;

}

.section{

padding:60px 0;

}

.hidden{

display:none;

}

.clear{

clear:both;

}

/*----------------------------------------------------------
04. TYPOGRAPHY
----------------------------------------------------------*/

h1,
h2,
h3,
h4,
h5,
h6{

font-weight:700;

color:var(--heading);

line-height:1.3;

margin-bottom:16px;

}

h1{

font-size:42px;

}

h2{

font-size:34px;

}

h3{

font-size:28px;

}

h4{

font-size:22px;

}

h5{

font-size:18px;

}

h6{

font-size:16px;

}

p{

margin-bottom:16px;

color:var(--text-light);

}

strong{

font-weight:700;

}

small{

font-size:13px;

}

/*----------------------------------------------------------
05. LINKS
----------------------------------------------------------*/

a:hover{

color:var(--primary);

}

/*----------------------------------------------------------
END OF PART 1B
----------------------------------------------------------*/
/*==========================================================
06. GRID SYSTEM
==========================================================*/

.row{
display:flex;
flex-wrap:wrap;
margin-left:-15px;
margin-right:-15px;
}

.col{
padding:15px;
flex:1;
}

.col-3{
width:25%;
padding:15px;
}

.col-4{
width:33.3333%;
padding:15px;
}

.col-6{
width:50%;
padding:15px;
}

.col-8{
width:66.6666%;
padding:15px;
}

.col-9{
width:75%;
padding:15px;
}

.col-12{
width:100%;
padding:15px;
}

/*==========================================================
07. BUTTONS
==========================================================*/

.btn{

display:inline-flex;

align-items:center;

justify-content:center;

padding:12px 28px;

border-radius:var(--radius);

font-weight:600;

cursor:pointer;

transition:var(--transition);

}

.btn-primary{

background:var(--primary);

color:#fff;

}

.btn-primary:hover{

background:var(--primary-dark);

}

.btn-outline{

border:2px solid var(--primary);

color:var(--primary);

}

.btn-outline:hover{

background:var(--primary);

color:#fff;

}

/*==========================================================
08. CARD
==========================================================*/

.card{

background:var(--card-bg);

border-radius:var(--radius);

box-shadow:var(--shadow);

overflow:hidden;

transition:var(--transition);

}

.card:hover{

transform:translateY(-5px);

}

/*==========================================================
09. UTILITIES
==========================================================*/

.text-center{text-align:center;}
.text-left{text-align:left;}
.text-right{text-align:right;}

.d-flex{display:flex;}
.flex-wrap{flex-wrap:wrap;}
.align-center{align-items:center;}
.justify-between{justify-content:space-between;}
.justify-center{justify-content:center;}

.w-100{width:100%;}

.mt-10{margin-top:10px;}
.mt-20{margin-top:20px;}
.mt-30{margin-top:30px;}

.mb-10{margin-bottom:10px;}
.mb-20{margin-bottom:20px;}
.mb-30{margin-bottom:30px;}

.pt-20{padding-top:20px;}
.pb-20{padding-bottom:20px;}

.radius{
border-radius:var(--radius);
}

.shadow{
box-shadow:var(--shadow);
}

/*==========================================================
10. SCROLLBAR
==========================================================*/

::-webkit-scrollbar{

width:10px;

}

::-webkit-scrollbar-thumb{

background:var(--primary);

border-radius:20px;

}

::-webkit-scrollbar-track{

background:#ececec;

}

/*==========================================================
11. TEXT SELECTION
==========================================================*/

::selection{

background:var(--primary);

color:#fff;

}

/*==========================================================
12. RESPONSIVE
==========================================================*/

@media(max-width:992px){

.col-3,
.col-4,
.col-6,
.col-8,
.col-9{

width:100%;

}

h1{

font-size:34px;

}

h2{

font-size:28px;

}

}

@media(max-width:768px){

.section{

padding:40px 0;

}

.container{

padding:0 15px;

}

}
/*==========================================================
HEADER
==========================================================*/

#site-header{

background:#fff;

position:sticky;

top:0;

left:0;

width:100%;

z-index:9999;

box-shadow:0 2px 12px rgba(0,0,0,.08);

}

/*==========================
TOP BAR
==========================*/

.topbar{

background:var(--primary);

color:#fff;

font-size:14px;

padding:8px 0;

}

.topbar-left,
.topbar-right{

display:flex;

align-items:center;

gap:8px;

}

.live-dot{

width:10px;

height:10px;

background:#ff0000;

border-radius:50%;

animation:liveBlink 1s infinite;

}

@keyframes liveBlink{

0%{opacity:1;}

50%{opacity:.3;}

100%{opacity:1;}

}

/*==========================
HEADER MAIN
==========================*/

.header-main{

background:#fff;

padding:18px 0;

}

.logo-title{

font-size:32px;

font-weight:800;

color:var(--primary);

margin:0;

}

.logo-tagline{

font-size:14px;

color:var(--text-light);

margin-top:4px;

}

/*==========================
HEADER BUTTONS
==========================*/

.header-actions{

display:flex;

align-items:center;

gap:12px;

}

.header-actions button{

width:44px;

height:44px;

border-radius:50%;

background:#f5f5f5;

cursor:pointer;

transition:var(--transition);

font-size:18px;

}

.header-actions button:hover{

background:var(--primary);

color:#fff;

}

/*==========================
NAVIGATION
==========================*/

.main-nav{

background:#ffffff;

border-top:1px solid var(--border);

border-bottom:1px solid var(--border);

}

.nav-menu{

display:flex;

align-items:center;

gap:28px;

}

.nav-menu li{

position:relative;

}

.nav-menu a{

display:block;

padding:16px 0;

font-size:15px;

font-weight:600;

transition:var(--transition);

}

.nav-menu a:hover{

color:var(--primary);

}

.nav-menu li::after{

content:"";

position:absolute;

left:0;

bottom:0;

width:0;

height:3px;

background:var(--primary);

transition:.3s;

}

.nav-menu li:hover::after{

width:100%;

}

/*==========================
RESPONSIVE HEADER
==========================*/

@media(max-width:992px){

.nav-menu{

display:none;

}

.logo-title{

font-size:26px;

}

.mobile-btn{

display:inline-flex;

}

}

@media(min-width:993px){

.mobile-btn{

display:none;

}

}
/*==========================================================
END OF FOUNDATION
==========================================================*/
/*==========================================================
BREAKING NEWS
==========================================================*/

#breaking-news-section{

margin:25px 0;

}

.breaking-news-wrap{

display:flex;

align-items:center;

background:#fff;

border-radius:10px;

overflow:hidden;

box-shadow:var(--shadow);

}

.breaking-label{

display:flex;

align-items:center;

gap:10px;

padding:15px 20px;

background:var(--primary);

color:#fff;

font-weight:700;

white-space:nowrap;

}

.live-indicator{

width:10px;

height:10px;

background:#ff0000;

border-radius:50%;

animation:blink 1s infinite;

}

@keyframes blink{

0%{opacity:1;}

50%{opacity:.2;}

100%{opacity:1;}

}

.breaking-widget{

flex:1;

padding:15px 20px;

font-size:15px;

}

/*==========================================================
HERO SECTION
==========================================================*/

#hero-wrapper{

margin:35px 0;

}

.featured-posts{

background:#fff;

border-radius:12px;

overflow:hidden;

box-shadow:var(--shadow);

min-height:420px;

}

.hero-sidebar{

display:flex;

flex-direction:column;

gap:20px;

}

.hero-sidebar .widget{

background:#fff;

padding:20px;

border-radius:12px;

box-shadow:var(--shadow);

}

/*==========================================================
WIDGET TITLE
==========================================================*/

.widget-title{

font-size:18px;

font-weight:700;

margin-bottom:15px;

padding-bottom:10px;

border-bottom:2px solid var(--primary);

}

/*==========================================================
RESPONSIVE
==========================================================*/

@media(max-width:992px){

.breaking-news-wrap{

flex-direction:column;

align-items:flex-start;

}

.breaking-label{

width:100%;

justify-content:center;

}

#hero-wrapper .row{

display:block;

}

.featured-posts{

margin-bottom:20px;

}

}/*==========================================================
DARK MODE
==========================================================*/

body.dark-mode{

background:#121212;

color:#eee;

}

body.dark-mode .header-main,

body.dark-mode .main-nav,

body.dark-mode .card{

background:#1e1e1e;

}

body.dark-mode a{

color:#fff;

}

/*==========================================================
STICKY
==========================================================*/

#header.sticky{

position:fixed;

top:0;

left:0;

width:100%;

z-index:9999;

animation:slideDown .3s;

}

@keyframes slideDown{

from{

transform:translateY(-100%);

}

to{

transform:translateY(0);

}

}

/*==========================================================
MOBILE MENU
==========================================================*/

@media(max-width:992px){

.main-nav{

display:none;

}

.main-nav.active{

display:block;

}

.menu-toggle{

display:block;

}

}

html.script:
document.addEventListener("DOMContentLoaded",function(){

/*=========================
LIVE DATE
=========================*/

const today=document.getElementById("today-date");

if(today){

const d=new Date();

today.innerHTML=d.toLocaleDateString("en-IN",{

weekday:"long",

day:"numeric",

month:"long",

year:"numeric"

});

}

/*=========================
DARK MODE
=========================*/

const darkBtn=document.getElementById("darkModeBtn");

if(darkBtn){

darkBtn.onclick=function(){

document.body.classList.toggle("dark-mode");

localStorage.setItem(

"theme",

document.body.classList.contains("dark-mode")

?"dark":"light"

);

};

if(localStorage.getItem("theme")=="dark"){

document.body.classList.add("dark-mode");

}

}

/*=========================
STICKY HEADER
=========================*/

window.addEventListener("scroll",function(){

const header=document.getElementById("header");

if(header){

if(window.scrollY>100){

header.classList.add("sticky");

}else{

header.classList.remove("sticky");

}

}

});

/*=========================
MOBILE MENU
=========================*/

const menu=document.querySelector(".main-nav");

const toggle=document.querySelector(".menu-toggle");

if(toggle){

toggle.onclick=function(){

menu.classList.toggle("active");

};

}

/*=========================
SEARCH
=========================*/

const searchBtn=document.getElementById("searchBtn");

if(searchBtn){

searchBtn.onclick=function(){

alert("Search Popup will be added in Module 4");

};

}

});
